#include <stdio.h>
int main()
{
    char s1[51], s2[51];
    unsigned short i = 0, j = 0;
    scanf("%s%s", s1, s2);
    while(s2[j] != '\0'){
        if(s1[i] == s2[j]){ i++; }
        j++;
    }
    printf("%hu", 1 + i);
    return 0;
}

