//! http://codeforces.com/contest/265/problem/A

fn main() {
  use std::io;
  let mut buf = String::new();
  io::stdin().read_line(&mut buf).unwrap();
  let s = buf.trim().to_string();
  buf.clear();
  io::stdin().read_line(&mut buf).unwrap();
  let t = buf.trim().to_string();
  let ss = s.as_bytes();

  let mut i = 1;
  for &u in t.as_bytes() {
    if u == ss[i-1] { i += 1; }
  }
  println!("{}", i);
}
